import { ClientSession } from "@modelcontextprotocol/sdk/client/index.js";
import { stdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";

// Create transport to local server
const transport = stdioClientTransport({
  command: "node",
  args: ["weather-server.js"]
});

// Create session
const session = new ClientSession(transport);
await session.initialize();  // Handshake

// Discover available tools
const tools = await session.listTools();

for (const tool of tools.tools) {
  console.log(`Tool: ${tool.name}`);
  console.log(`Description: ${tool.description}`);
  console.log(`Schema: ${JSON.stringify(tool.inputSchema)}`);
}

// Invoke a tool
const result = await session.callTool({
  name: "get_weather",
  arguments: {
    location: "San Francisco",
    units: "fahrenheit"
  }
});

console.log(result.content); // Array of {type, text}

// Discover resources
const resources = await session.listResources();

for (const resource of resources.resources) {
  console.log(`${resource.name}: ${resource.uri}`);
}

// Read a resource
const content = await session.readResource({
  uri: "file:///logs/app.log"
});

console.log(content.contents); // Text content

// Discover prompts
const prompts = await session.listPrompts();

for (const prompt of prompts.prompts) {
  console.log(`${prompt.name}: ${prompt.description}`);
}

// Get rendered prompt
const rendered = await session.getPrompt({
  name: "write_blog_post",
  arguments: {
    topic: "AI in Healthcare",
    style: "technical"
  }
});

console.log(rendered.messages); // Array of {role, content}
